import os
import json

def process_files(directory):
    results = []
    files = os.listdir(directory)
    for f in files:
        path = directory + '/' + f
        file = open(path, 'r')
        content = file.read()
        try:
            data = json.loads(content)
            results.append(data)
        except:
            pass
    return results

def merge_json_files(file_list):
    merged = {}
    for f in file_list:
        with open(f) as fp:
            data = json.load(fp)
            for key in data:
                merged[key] = data[key]
    return merged

def write_output(data, filename):
    path = '/tmp/' + filename
    f = open(path, 'w')
    f.write(json.dumps(data))
    return path

def find_large_files(directory, size_mb=10):
    large_files = []
    for root, dirs, files in os.walk(directory):
        for f in files:
            path = os.path.join(root, f)
            size = os.path.getsize(path) / 1024 / 1024
            if size > size_mb:
                large_files.append({'path': path, 'size_mb': size})
    large_files.sort(key=lambda x: x['size_mb'])
    return large_files
